// frontend/src/pages/Admin/UserManagement.js

import React, { useState, useEffect, useCallback } from 'react';
import { usePermissions } from '../../hooks/usePermissions';
import { useAPI } from '../../hooks/useAPI';
import DataTable from '../../components/common/DataTable';
import Modal from '../../components/common/Modal';
import ConfirmDialog from '../../components/common/ConfirmDialog';
import Toast from '../../components/common/Toast';
import SearchBox from '../../components/common/SearchBox';
import './UserManagement.css';

const UserManagement = () => {
  const { canPerformAction } = usePermissions();
  const { get, post, put, del } = useAPI();

  // State management
  const [users, setUsers] = useState([]);
  const [roles, setRoles] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedUser, setSelectedUser] = useState(null);
  const [showUserModal, setShowUserModal] = useState(false);
  const [showRoleModal, setShowRoleModal] = useState(false);
  const [showConfirmDialog, setShowConfirmDialog] = useState(false);
  const [confirmAction, setConfirmAction] = useState(null);
  const [toast, setToast] = useState({ show: false, type: '', message: '' });

  // Filters
  const [filters, setFilters] = useState({
    status: 'all',
    user_type: 'all',
    role: 'all'
  });

  // Pagination
  const [pagination, setPagination] = useState({
    page: 1,
    limit: 20,
    total: 0
  });

  // Form data for user creation/editing
  const [userForm, setUserForm] = useState({
    username: '',
    email: '',
    first_name: '',
    last_name: '',
    phone: '',
    address: '',
    user_type: 'staff',
    status: 'pending',
    password: '',
    confirm_password: '',
    warehouse_access: [],
    notification_enabled: true,
    email_notification: true
  });

  // User role assignment form
  const [roleForm, setRoleForm] = useState({
    user_id: null,
    role_ids: [],
    reason: '',
    expires_at: null
  });

  // Load data
  const loadUsers = useCallback(async () => {
    try {
      setLoading(true);
      const params = new URLSearchParams({
        page: pagination.page,
        limit: pagination.limit,
        search: searchTerm,
        ...filters
      });

      const response = await get(`/api/admin/users?${params}`);

      if (response.success) {
        setUsers(response.data.results);
        setPagination(prev => ({
          ...prev,
          total: response.data.total
        }));
      }
    } catch (error) {
      showToast('error', 'Không thể tải danh sách người dùng');
    } finally {
      setLoading(false);
    }
  }, [pagination.page, pagination.limit, searchTerm, filters, get]);

  const loadRoles = useCallback(async () => {
    try {
      const response = await get('/api/admin/roles?status=active');
      if (response.success) {
        setRoles(response.data);
      }
    } catch (error) {
      showToast('error', 'Không thể tải danh sách vai trò');
    }
  }, [get]);

  useEffect(() => {
    loadUsers();
  }, [loadUsers]);

  useEffect(() => {
    loadRoles();
  }, [loadRoles]);

  // Helper functions
  const showToast = (type, message) => {
    setToast({ show: true, type, message });
    setTimeout(() => setToast({ show: false, type: '', message: '' }), 5000);
  };

  const resetUserForm = () => {
    setUserForm({
      username: '',
      email: '',
      first_name: '',
      last_name: '',
      phone: '',
      address: '',
      user_type: 'staff',
      status: 'pending',
      password: '',
      confirm_password: '',
      warehouse_access: [],
      notification_enabled: true,
      email_notification: true
    });
  };

  // User management functions
  const handleCreateUser = () => {
    if (!canPerformAction('user_management', 'create')) {
      showToast('error', 'Bạn không có quyền tạo người dùng');
      return;
    }

    resetUserForm();
    setSelectedUser(null);
    setShowUserModal(true);
  };

  const handleEditUser = (user) => {
    if (!canPerformAction('user_management', 'edit')) {
      showToast('error', 'Bạn không có quyền chỉnh sửa người dùng');
      return;
    }

    setSelectedUser(user);
    setUserForm({
      username: user.username,
      email: user.email,
      first_name: user.first_name || '',
      last_name: user.last_name || '',
      phone: user.phone || '',
      address: user.address || '',
      user_type: user.user_type,
      status: user.status,
      password: '',
      confirm_password: '',
      warehouse_access: user.warehouse_access || [],
      notification_enabled: user.notification_enabled,
      email_notification: user.email_notification
    });
    setShowUserModal(true);
  };

  const handleDeleteUser = (user) => {
    if (!canPerformAction('user_management', 'delete')) {
      showToast('error', 'Bạn không có quyền xóa người dùng');
      return;
    }

    setConfirmAction({
      type: 'delete_user',
      user: user,
      title: 'Xác nhận xóa người dùng',
      message: `Bạn có chắc chắn muốn xóa người dùng "${user.get_full_name}"? Hành động này không thể hoàn tác.`,
      confirmText: 'Xóa',
      cancelText: 'Hủy'
    });
    setShowConfirmDialog(true);
  };

  const handleToggleUserStatus = (user) => {
    const newStatus = user.status === 'active' ? 'inactive' : 'active';
    const action = newStatus === 'active' ? 'kích hoạt' : 'vô hiệu hóa';

    setConfirmAction({
      type: 'toggle_status',
      user: user,
      newStatus: newStatus,
      title: `Xác nhận ${action} người dùng`,
      message: `Bạn có chắc chắn muốn ${action} người dùng "${user.get_full_name}"?`,
      confirmText: newStatus === 'active' ? 'Kích hoạt' : 'Vô hiệu hóa',
      cancelText: 'Hủy'
    });
    setShowConfirmDialog(true);
  };

  const handleManageUserRoles = (user) => {
    if (!canPerformAction('user_management', 'assign')) {
      showToast('error', 'Bạn không có quyền phân quyền người dùng');
      return;
    }

    setRoleForm({
      user_id: user.id,
      role_ids: user.user_roles?.map(ur => ur.role.id) || [],
      reason: '',
      expires_at: null
    });
    setSelectedUser(user);
    setShowRoleModal(true);
  };

  // Form submission handlers
  const handleSubmitUser = async (e) => {
    e.preventDefault();

    try {
      // Validate form
      if (!userForm.username || !userForm.email) {
        showToast('error', 'Vui lòng điền đầy đủ thông tin bắt buộc');
        return;
      }

      if (!selectedUser && (!userForm.password || userForm.password !== userForm.confirm_password)) {
        showToast('error', 'Mật khẩu không khớp hoặc để trống');
        return;
      }

      const userData = { ...userForm };
      delete userData.confirm_password;

      let response;
      if (selectedUser) {
        // Update existing user
        response = await put(`/api/admin/users/${selectedUser.id}`, userData);
      } else {
        // Create new user
        response = await post('/api/admin/users', userData);
      }

      if (response.success) {
        showToast('success', selectedUser ? 'Cập nhật người dùng thành công' : 'Tạo người dùng thành công');
        setShowUserModal(false);
        loadUsers();
      } else {
        showToast('error', response.message || 'Có lỗi xảy ra');
      }
    } catch (error) {
      showToast('error', 'Không thể lưu thông tin người dùng');
    }
  };

  const handleSubmitRoles = async (e) => {
    e.preventDefault();

    try {
      const response = await post(`/api/admin/users/${roleForm.user_id}/roles`, {
        role_ids: roleForm.role_ids,
        reason: roleForm.reason,
        expires_at: roleForm.expires_at
      });

      if (response.success) {
        showToast('success', 'Cập nhật vai trò thành công');
        setShowRoleModal(false);
        loadUsers();
      } else {
        showToast('error', response.message || 'Có lỗi xảy ra');
      }
    } catch (error) {
      showToast('error', 'Không thể cập nhật vai trò');
    }
  };

  const handleConfirmAction = async () => {
    try {
      if (confirmAction.type === 'delete_user') {
        const response = await del(`/api/admin/users/${confirmAction.user.id}`);
        if (response.success) {
          showToast('success', 'Xóa người dùng thành công');
          loadUsers();
        }
      } else if (confirmAction.type === 'toggle_status') {
        const response = await put(`/api/admin/users/${confirmAction.user.id}/status`, {
          status: confirmAction.newStatus
        });
        if (response.success) {
          showToast('success', `${confirmAction.newStatus === 'active' ? 'Kích hoạt' : 'Vô hiệu hóa'} người dùng thành công`);
          loadUsers();
        }
      }
    } catch (error) {
      showToast('error', 'Không thể thực hiện hành động');
    }

    setShowConfirmDialog(false);
    setConfirmAction(null);
  };

  // Table columns configuration
  const columns = [
    {
      key: 'avatar',
      title: '',
      render: (user) => (
        <div className="user-avatar">
          {user.avatar_url ? (
            <img src={user.avatar_url} alt={user.get_full_name} />
          ) : (
            <div className="avatar-placeholder">
              {user.get_full_name?.charAt(0)?.toUpperCase() || 'U'}
            </div>
          )}
        </div>
      ),
      width: '60px'
    },
    {
      key: 'user_info',
      title: 'Thông tin người dùng',
      render: (user) => (
        <div className="user-info">
          <div className="user-name">{user.get_full_name}</div>
          <div className="user-details">
            <span className="username">@{user.username}</span>
            <span className="email">{user.email}</span>
          </div>
          {user.employee_id && (
            <div className="employee-id">Mã NV: {user.employee_id}</div>
          )}
        </div>
      )
    },
    {
      key: 'user_type',
      title: 'Loại tài khoản',
      render: (user) => (
        <span className={`user-type-badge ${user.user_type}`}>
          {getUserTypeDisplay(user.user_type)}
        </span>
      )
    },
    {
      key: 'roles',
      title: 'Vai trò',
      render: (user) => (
        <div className="user-roles">
          {user.user_roles?.map(role => (
            <span key={role.id} className="role-badge">
              {role.role.name}
            </span>
          )) || <span className="no-roles">Chưa có vai trò</span>}
        </div>
      )
    },
    {
      key: 'status',
      title: 'Trạng thái',
      render: (user) => (
        <span className={`status-badge ${user.status}`}>
          {getStatusDisplay(user.status)}
        </span>
      )
    },
    {
      key: 'last_login',
      title: 'Đăng nhập cuối',
      render: (user) => (
        <div className="last-login">
          {user.last_login ? (
            <>
              <div>{new Date(user.last_login).toLocaleDateString('vi-VN')}</div>
              <div className="time">{new Date(user.last_login).toLocaleTimeString('vi-VN')}</div>
            </>
          ) : (
            <span className="never">Chưa đăng nhập</span>
          )}
        </div>
      )
    },
    {
      key: 'actions',
      title: 'Thao tác',
      render: (user) => (
        <div className="action-buttons">
          <button
            className="btn btn-sm btn-primary"
            onClick={() => handleEditUser(user)}
            title="Chỉnh sửa"
          >
            <i className="icon-edit"></i>
          </button>

          <button
            className="btn btn-sm btn-secondary"
            onClick={() => handleManageUserRoles(user)}
            title="Quản lý vai trò"
          >
            <i className="icon-users"></i>
          </button>

          <button
            className={`btn btn-sm ${user.status === 'active' ? 'btn-warning' : 'btn-success'}`}
            onClick={() => handleToggleUserStatus(user)}
            title={user.status === 'active' ? 'Vô hiệu hóa' : 'Kích hoạt'}
          >
            <i className={user.status === 'active' ? 'icon-user-x' : 'icon-user-check'}></i>
          </button>

          {canPerformAction('user_management', 'delete') && user.user_type !== 'admin' && (
            <button
              className="btn btn-sm btn-danger"
              onClick={() => handleDeleteUser(user)}
              title="Xóa"
            >
              <i className="icon-trash-2"></i>
            </button>
          )}
        </div>
      ),
      width: '200px'
    }
  ];

  // Helper functions for display
  const getUserTypeDisplay = (type) => {
    const types = {
      admin: 'Quản trị viên',
      manager: 'Quản lý',
      supervisor: 'Giám sát',
      staff: 'Nhân viên',
      viewer: 'Chỉ xem',
      delivery: 'Giao hàng',
      quality: 'Kiểm tra CL'
    };
    return types[type] || type;
  };

  const getStatusDisplay = (status) => {
    const statuses = {
      active: 'Hoạt động',
      inactive: 'Không hoạt động',
      suspended: 'Tạm dừng',
      pending: 'Chờ duyệt'
    };
    return statuses[status] || status;
  };

  // Filter users based on search and filters
  const filteredUsers = users.filter(user => {
    const matchesSearch = !searchTerm || 
      user.get_full_name?.toLowerCase().includes(searchTerm.toLowerCase()) ||
      user.username.toLowerCase().includes(searchTerm.toLowerCase()) ||
      user.email.toLowerCase().includes(searchTerm.toLowerCase());

    const matchesStatus = filters.status === 'all' || user.status === filters.status;
    const matchesUserType = filters.user_type === 'all' || user.user_type === filters.user_type;
    const matchesRole = filters.role === 'all' || 
      user.user_roles?.some(ur => ur.role.id === parseInt(filters.role));

    return matchesSearch && matchesStatus && matchesUserType && matchesRole;
  });

  if (!canPerformAction('user_management', 'view')) {
    return (
      <div className="access-denied">
        <h3>Không có quyền truy cập</h3>
        <p>Bạn không có quyền xem trang quản lý người dùng.</p>
      </div>
    );
  }

  return (
    <div className="user-management">
      <div className="page-header">
        <div className="header-content">
          <h1>
            <i className="icon-users"></i>
            Quản lý Người dùng
          </h1>
          <p>Quản lý tài khoản và phân quyền người dùng trong hệ thống</p>
        </div>

        {canPerformAction('user_management', 'create') && (
          <button 
            className="btn btn-primary"
            onClick={handleCreateUser}
          >
            <i className="icon-user-plus"></i>
            Thêm người dùng
          </button>
        )}
      </div>

      {/* Filters and Search */}
      <div className="filters-section">
        <div className="search-filters">
          <SearchBox
            value={searchTerm}
            onChange={setSearchTerm}
            placeholder="Tìm kiếm theo tên, username hoặc email..."
          />

          <div className="filter-group">
            <select
              value={filters.status}
              onChange={(e) => setFilters(prev => ({ ...prev, status: e.target.value }))}
              className="filter-select"
            >
              <option value="all">Tất cả trạng thái</option>
              <option value="active">Hoạt động</option>
              <option value="inactive">Không hoạt động</option>
              <option value="suspended">Tạm dừng</option>
              <option value="pending">Chờ duyệt</option>
            </select>

            <select
              value={filters.user_type}
              onChange={(e) => setFilters(prev => ({ ...prev, user_type: e.target.value }))}
              className="filter-select"
            >
              <option value="all">Tất cả loại tài khoản</option>
              <option value="admin">Quản trị viên</option>
              <option value="manager">Quản lý</option>
              <option value="supervisor">Giám sát</option>
              <option value="staff">Nhân viên</option>
              <option value="viewer">Chỉ xem</option>
              <option value="delivery">Giao hàng</option>
              <option value="quality">Kiểm tra CL</option>
            </select>

            <select
              value={filters.role}
              onChange={(e) => setFilters(prev => ({ ...prev, role: e.target.value }))}
              className="filter-select"
            >
              <option value="all">Tất cả vai trò</option>
              {roles.map(role => (
                <option key={role.id} value={role.id}>{role.name}</option>
              ))}
            </select>
          </div>
        </div>

        <div className="results-info">
          Hiển thị {filteredUsers.length} / {users.length} người dùng
        </div>
      </div>

      {/* Users Table */}
      <div className="table-section">
        <DataTable
          columns={columns}
          data={filteredUsers}
          loading={loading}
          pagination={pagination}
          onPageChange={(page) => setPagination(prev => ({ ...prev, page }))}
          emptyMessage="Không có người dùng nào"
        />
      </div>

      {/* User Modal */}
      {showUserModal && (
        <Modal
          title={selectedUser ? 'Chỉnh sửa người dùng' : 'Thêm người dùng mới'}
          isOpen={showUserModal}
          onClose={() => setShowUserModal(false)}
          size="large"
        >
          <form onSubmit={handleSubmitUser} className="user-form">
            <div className="form-grid">
              <div className="form-group">
                <label htmlFor="username">Tên đăng nhập *</label>
                <input
                  type="text"
                  id="username"
                  value={userForm.username}
                  onChange={(e) => setUserForm(prev => ({ ...prev, username: e.target.value }))}
                  required
                  disabled={!!selectedUser}
                />
              </div>

              <div className="form-group">
                <label htmlFor="email">Email *</label>
                <input
                  type="email"
                  id="email"
                  value={userForm.email}
                  onChange={(e) => setUserForm(prev => ({ ...prev, email: e.target.value }))}
                  required
                />
              </div>

              <div className="form-group">
                <label htmlFor="first_name">Tên</label>
                <input
                  type="text"
                  id="first_name"
                  value={userForm.first_name}
                  onChange={(e) => setUserForm(prev => ({ ...prev, first_name: e.target.value }))}
                />
              </div>

              <div className="form-group">
                <label htmlFor="last_name">Họ</label>
                <input
                  type="text"
                  id="last_name"
                  value={userForm.last_name}
                  onChange={(e) => setUserForm(prev => ({ ...prev, last_name: e.target.value }))}
                />
              </div>

              <div className="form-group">
                <label htmlFor="phone">Số điện thoại</label>
                <input
                  type="tel"
                  id="phone"
                  value={userForm.phone}
                  onChange={(e) => setUserForm(prev => ({ ...prev, phone: e.target.value }))}
                />
              </div>

              <div className="form-group">
                <label htmlFor="user_type">Loại tài khoản</label>
                <select
                  id="user_type"
                  value={userForm.user_type}
                  onChange={(e) => setUserForm(prev => ({ ...prev, user_type: e.target.value }))}
                >
                  <option value="staff">Nhân viên</option>
                  <option value="supervisor">Giám sát</option>
                  <option value="manager">Quản lý</option>
                  <option value="viewer">Chỉ xem</option>
                  <option value="delivery">Giao hàng</option>
                  <option value="quality">Kiểm tra CL</option>
                  {canPerformAction('user_management', 'manage_users') && (
                    <option value="admin">Quản trị viên</option>
                  )}
                </select>
              </div>
            </div>

            <div className="form-group full-width">
              <label htmlFor="address">Địa chỉ</label>
              <textarea
                id="address"
                value={userForm.address}
                onChange={(e) => setUserForm(prev => ({ ...prev, address: e.target.value }))}
                rows={3}
              />
            </div>

            {!selectedUser && (
              <div className="form-grid">
                <div className="form-group">
                  <label htmlFor="password">Mật khẩu *</label>
                  <input
                    type="password"
                    id="password"
                    value={userForm.password}
                    onChange={(e) => setUserForm(prev => ({ ...prev, password: e.target.value }))}
                    required={!selectedUser}
                    minLength={6}
                  />
                </div>

                <div className="form-group">
                  <label htmlFor="confirm_password">Xác nhận mật khẩu *</label>
                  <input
                    type="password"
                    id="confirm_password"
                    value={userForm.confirm_password}
                    onChange={(e) => setUserForm(prev => ({ ...prev, confirm_password: e.target.value }))}
                    required={!selectedUser}
                    minLength={6}
                  />
                </div>
              </div>
            )}

            <div className="form-group">
              <label htmlFor="status">Trạng thái</label>
              <select
                id="status"
                value={userForm.status}
                onChange={(e) => setUserForm(prev => ({ ...prev, status: e.target.value }))}
              >
                <option value="pending">Chờ duyệt</option>
                <option value="active">Hoạt động</option>
                <option value="inactive">Không hoạt động</option>
                <option value="suspended">Tạm dừng</option>
              </select>
            </div>

            <div className="form-options">
              <label className="checkbox-label">
                <input
                  type="checkbox"
                  checked={userForm.notification_enabled}
                  onChange={(e) => setUserForm(prev => ({ ...prev, notification_enabled: e.target.checked }))}
                />
                <span>Bật thông báo</span>
              </label>

              <label className="checkbox-label">
                <input
                  type="checkbox"
                  checked={userForm.email_notification}
                  onChange={(e) => setUserForm(prev => ({ ...prev, email_notification: e.target.checked }))}
                />
                <span>Nhận thông báo qua email</span>
              </label>
            </div>

            <div className="form-actions">
              <button type="button" className="btn btn-secondary" onClick={() => setShowUserModal(false)}>
                Hủy
              </button>
              <button type="submit" className="btn btn-primary">
                {selectedUser ? 'Cập nhật' : 'Tạo mới'}
              </button>
            </div>
          </form>
        </Modal>
      )}

      {/* Role Assignment Modal */}
      {showRoleModal && (
        <Modal
          title={`Quản lý vai trò - ${selectedUser?.get_full_name}`}
          isOpen={showRoleModal}
          onClose={() => setShowRoleModal(false)}
          size="medium"
        >
          <form onSubmit={handleSubmitRoles} className="role-form">
            <div className="current-roles">
              <h4>Vai trò hiện tại:</h4>
              <div className="role-list">
                {selectedUser?.user_roles?.map(userRole => (
                  <div key={userRole.id} className="role-item">
                    <span className="role-name">{userRole.role.name}</span>
                    <span className="role-info">
                      Gán: {new Date(userRole.assigned_at).toLocaleDateString('vi-VN')}
                      {userRole.expires_at && (
                        <> | Hết hạn: {new Date(userRole.expires_at).toLocaleDateString('vi-VN')}</>
                      )}
                    </span>
                  </div>
                ))}
              </div>
            </div>

            <div className="form-group">
              <label>Chọn vai trò mới:</label>
              <div className="role-checkboxes">
                {roles.map(role => (
                  <label key={role.id} className="checkbox-label">
                    <input
                      type="checkbox"
                      checked={roleForm.role_ids.includes(role.id)}
                      onChange={(e) => {
                        if (e.target.checked) {
                          setRoleForm(prev => ({
                            ...prev,
                            role_ids: [...prev.role_ids, role.id]
                          }));
                        } else {
                          setRoleForm(prev => ({
                            ...prev,
                            role_ids: prev.role_ids.filter(id => id !== role.id)
                          }));
                        }
                      }}
                    />
                    <span>{role.name}</span>
                    <small>{role.description}</small>
                  </label>
                ))}
              </div>
            </div>

            <div className="form-group">
              <label htmlFor="role_reason">Lý do thay đổi:</label>
              <textarea
                id="role_reason"
                value={roleForm.reason}
                onChange={(e) => setRoleForm(prev => ({ ...prev, reason: e.target.value }))}
                placeholder="Mô tả lý do thay đổi vai trò..."
                rows={3}
              />
            </div>

            <div className="form-group">
              <label htmlFor="expires_at">Thời hạn (tùy chọn):</label>
              <input
                type="datetime-local"
                id="expires_at"
                value={roleForm.expires_at || ''}
                onChange={(e) => setRoleForm(prev => ({ ...prev, expires_at: e.target.value }))}
              />
            </div>

            <div className="form-actions">
              <button type="button" className="btn btn-secondary" onClick={() => setShowRoleModal(false)}>
                Hủy
              </button>
              <button type="submit" className="btn btn-primary">
                Cập nhật vai trò
              </button>
            </div>
          </form>
        </Modal>
      )}

      {/* Confirm Dialog */}
      {showConfirmDialog && confirmAction && (
        <ConfirmDialog
          isOpen={showConfirmDialog}
          title={confirmAction.title}
          message={confirmAction.message}
          confirmText={confirmAction.confirmText}
          cancelText={confirmAction.cancelText}
          onConfirm={handleConfirmAction}
          onCancel={() => {
            setShowConfirmDialog(false);
            setConfirmAction(null);
          }}
          type={confirmAction.type === 'delete_user' ? 'danger' : 'warning'}
        />
      )}

      {/* Toast Notification */}
      {toast.show && (
        <Toast
          type={toast.type}
          message={toast.message}
          onClose={() => setToast({ show: false, type: '', message: '' })}
        />
      )}
    </div>
  );
};

export default UserManagement;
